& { $path = "$env:downloads"; $days = 30; $cutoff = (Get-Date).AddDays(-$days); $files = Get-ChildItem -Path $path -Recurse -File | Where-Object { $_.LastWriteTime -lt $cutoff }; $count = if ($files) { $files.Count } else { 0 }; $files | Remove-Item -Force -ErrorAction SilentlyContinue; Write-Host ''; Write-Host 'Deleted ' -NoNewline; Write-Host $count -ForegroundColor Green -NoNewline; Write-Host ' files older than ' -NoNewline; Write-Host $days -NoNewline; Write-Host ' days.' }
